module uart_transmitter (
    input wire clk,
    input wire start,
    input wire [7:0] data,
    output reg tx
);
    reg [3:0] uart_tx_state;
    reg [3:0] count;
    parameter IDLE = 0, START = 1, DATA = 2, STOP = 3;

    always @(posedge clk) begin
        case (uart_tx_state)
            IDLE: begin
                tx <= 1; // idle uart_tx_state is high
                if (start) begin
                    uart_tx_state <= START;
                    count <= 0;
                end
            end

            START: begin
                tx <= 0; // start bit
                uart_tx_state <= DATA;
                count <= 0;
            end

            DATA: begin
                tx <= data[count]; // transmit data bits
                if (count < 7) begin
                    count <= count + 1;
                end else begin
                    uart_tx_state <= STOP;
                end
            end

            STOP: begin
                tx <= 1; // stop bit
                uart_tx_state <= IDLE;
            end
        endcase
    end
endmodule
